# vault-policy-summarizer-agent.hcl
# Summarizer agent: read-only access to Anthropic API key.
# No access to database, signing keys, or admin credentials.

# Read the Anthropic API key
path "secret/data/prod/llm/anthropic" {
  capabilities = ["read"]
}

# Read metadata to check if the secret exists (used by health checks)
path "secret/metadata/prod/llm/anthropic" {
  capabilities = ["read"]
}

# Explicitly deny access to database credentials
path "secret/data/prod/db/*" {
  capabilities = ["deny"]
}

# Explicitly deny admin and rotation credentials
path "secret/data/prod/admin/*" {
  capabilities = ["deny"]
}

# Allow token self-renewal
path "auth/token/renew-self" {
  capabilities = ["update"]
}

"""access_review.py

Quarterly access review: identifies policies that grant access to secrets
no longer read by the service in the past 90 days, based on Vault audit logs.
"""
import json
from collections import defaultdict
from datetime import datetime, timedelta


def load_audit_log(path: str) -> list[dict]:
    with open(path) as f:
        return [json.loads(line) for line in f if line.strip()]


def get_secrets_read_by_identity(
    audit_log: list[dict], days: int = 90
) -> dict[str, set[str]]:
    cutoff = datetime.utcnow() - timedelta(days=days)
    reads: dict[str, set[str]] = defaultdict(set)
    for entry in audit_log:
        ts = datetime.fromisoformat(entry["time"].rstrip("Z"))
        if ts < cutoff:
            continue
        if entry.get("type") != "response":
            continue
        auth = entry.get("auth", {})
        identity = auth.get("display_name", "unknown")
        path = entry.get("request", {}).get("path", "")
        if entry.get("error") is None:  # successful read
            reads[identity].add(path)
    return reads


def review_policy(policy_grants: dict[str, list[str]], reads: dict[str, set[str]]) -> None:
    for identity, allowed_paths in policy_grants.items():
        actual_reads = reads.get(identity, set())
        for path in allowed_paths:
            if not any(r.startswith(path.rstrip("*")) for r in actual_reads):
                print(
                    f"REVIEW: {identity} has policy access to {path} "
                    f"but made no reads in the last 90 days. Consider removing."
                )


if __name__ == "__main__":
    audit = load_audit_log("/var/log/vault/audit.log")
    reads = get_secrets_read_by_identity(audit)
    policy_grants = {
        "summarizer-agent": ["secret/data/prod/llm/anthropic"],
        "codereviewer-agent": ["secret/data/prod/llm/anthropic", "secret/data/prod/vcs/github"],
        "deploy-job": ["secret/data/prod/infra/registry"],
    }
    review_policy(policy_grants, reads)
